namespace WhatsFlow.Infrastructure.Services;

public static class EmailTemplates
{
    private const string AppUrl = "https://app.verboplus.com.br";
    private const string LogoDataUri = "data:image/png;base64,";
    private const string PrimaryColor = "#7C3AED";
    private const string SecondaryColor = "#2563EB";
    private const string ColorSchemeStyle = "<style>:root{color-scheme:dark;}</style>";

    public static string VerificacaoEmail(string nome, string linkConfirmacao, int validaHoras) => Layout(
        preview: "Confirme seu e-mail para ativar o Verbo+",
        body: $"""
            <h1 style="margin:0 0 12px;font-size:26px;font-weight:700;color:#F1F5F9;">Bem-vindo ao Verbo+, {EscapeHtml(nome)}!</h1>
            <p style="margin:0 0 28px;color:#94A3B8;line-height:1.7;font-size:16px;">
                Sua organização foi criada com sucesso. Para ativar o acesso, confirme seu e-mail clicando no botão abaixo.
            </p>
            {Botao("Confirmar meu e-mail", linkConfirmacao)}
            <p style="margin:28px 0 0;font-size:13px;color:#64748B;line-height:1.6;">
                O link expira em <strong style="color:#94A3B8;">{validaHoras} horas</strong>. Se você não criou uma conta no Verbo+, ignore este e-mail.
            </p>
            <p style="margin:10px 0 0;font-size:13px;color:#64748B;">
                Ou cole este link no navegador:<br/>
                <a href="{linkConfirmacao}" style="color:{PrimaryColor};word-break:break-all;">{linkConfirmacao}</a>
            </p>
        """
    );

    public static string TrialAcabando(string nomeOrganizacao, DateTime trialFim) => Layout(
        preview: $"Seu período de teste termina em {trialFim:dd/MM}",
        body: $"""
            <h1 style="margin:0 0 12px;font-size:26px;font-weight:700;color:#F1F5F9;">Seu período de teste está acabando</h1>
            <p style="margin:0 0 16px;color:#94A3B8;line-height:1.7;font-size:16px;">
                O período de teste da organização <strong style="color:#E2E8F0;">{EscapeHtml(nomeOrganizacao)}</strong> termina em
                <strong style="color:#E2E8F0;">{trialFim:dd/MM/yyyy}</strong>.
            </p>
            <p style="margin:0 0 28px;color:#94A3B8;line-height:1.7;font-size:16px;">
                Para continuar com acesso completo sem interrupção, assine agora. Você pode cancelar a qualquer momento.
            </p>
            {Botao("Escolher meu plano", $"{AppUrl}/assinatura")}
            <p style="margin:28px 0 0;font-size:13px;color:#64748B;">
                Dúvidas? Responda este e-mail ou acesse o painel em <a href="{AppUrl}" style="color:{PrimaryColor};">app.verboplus.com.br</a>.
            </p>
        """
    );

    public static string AssinaturaSuspensa(string nomeOrganizacao) => Layout(
        preview: "Sua assinatura foi suspensa por falta de pagamento",
        body: $"""
            <div style="background:rgba(239,68,68,0.12);border:1px solid rgba(239,68,68,0.3);border-radius:8px;padding:14px 18px;margin:0 0 28px;">
                <p style="margin:0;font-size:14px;font-weight:600;color:#FCA5A5;">⚠️ Acesso suspenso</p>
            </div>
            <h1 style="margin:0 0 12px;font-size:26px;font-weight:700;color:#F1F5F9;">Assinatura suspensa</h1>
            <p style="margin:0 0 16px;color:#94A3B8;line-height:1.7;font-size:16px;">
                A assinatura da organização <strong style="color:#E2E8F0;">{EscapeHtml(nomeOrganizacao)}</strong> foi suspensa por falta de pagamento.
            </p>
            <p style="margin:0 0 28px;color:#94A3B8;line-height:1.7;font-size:16px;">
                Para reativar o acesso, regularize o pagamento na área de Assinatura. Seus dados estão preservados.
            </p>
            {Botao("Regularizar pagamento", $"{AppUrl}/assinatura")}
            <p style="margin:28px 0 0;font-size:13px;color:#64748B;">
                Precisa de ajuda? Entre em contato com o suporte respondendo este e-mail.
            </p>
        """
    );

    public static string PagamentoPendente(string nomeOrganizacao) => Layout(
        preview: "Identificamos uma pendência de pagamento na sua assinatura",
        body: $"""
            <div style="background:rgba(245,158,11,0.12);border:1px solid rgba(245,158,11,0.3);border-radius:8px;padding:14px 18px;margin:0 0 28px;">
                <p style="margin:0;font-size:14px;font-weight:600;color:#FCD34D;">⚡ Ação necessária</p>
            </div>
            <h1 style="margin:0 0 12px;font-size:26px;font-weight:700;color:#F1F5F9;">Pagamento pendente</h1>
            <p style="margin:0 0 16px;color:#94A3B8;line-height:1.7;font-size:16px;">
                Identificamos uma pendência de pagamento na assinatura de <strong style="color:#E2E8F0;">{EscapeHtml(nomeOrganizacao)}</strong>.
            </p>
            <p style="margin:0 0 28px;color:#94A3B8;line-height:1.7;font-size:16px;">
                Regularize agora para evitar a suspensão do acesso. O processo leva menos de 2 minutos.
            </p>
            {Botao("Regularizar agora", $"{AppUrl}/assinatura")}
            <p style="margin:28px 0 0;font-size:13px;color:#64748B;">
                Se o pagamento já foi realizado, desconsidere este aviso. Pode levar algumas horas para ser processado.
            </p>
        """
    );

    private static string Botao(string texto, string url) => $"""
        <a href="{url}"
           style="display:inline-block;background:linear-gradient(135deg,{PrimaryColor},{SecondaryColor});
                  color:#ffffff;font-weight:700;font-size:15px;text-decoration:none;
                  padding:14px 28px;border-radius:10px;letter-spacing:0.01em;">
            {texto} →
        </a>
        """;

    private static string Layout(string preview, string body) => $"""
        <!DOCTYPE html>
        <html lang="pt-BR">
        <head>
          <meta charset="UTF-8"/>
          <meta name="viewport" content="width=device-width,initial-scale=1"/>
          <meta name="color-scheme" content="light only"/>
          <meta name="supported-color-schemes" content="light"/>
          <title>Verbo+</title>
          {ColorSchemeStyle}
        </head>
        <body style="margin:0;padding:0;background-color:#0F172A;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">
          <!-- preview text (hidden) -->
          <div style="display:none;max-height:0;overflow:hidden;mso-hide:all;">
            {EscapeHtml(preview)}&nbsp;&#847;&nbsp;&#847;&nbsp;&#847;&nbsp;&#847;&nbsp;&#847;
          </div>

          <table width="100%" cellpadding="0" cellspacing="0" style="background-color:#0F172A;padding:0;">
            <tr><td align="center">
              <table width="100%" style="max-width:580px;" cellpadding="0" cellspacing="0">

                <!-- Top gradient stripe -->
                <tr>
                  <td style="background:linear-gradient(90deg,#7C3AED,#2563EB);height:3px;line-height:3px;font-size:0;">&nbsp;</td>
                </tr>

                <!-- Logo section -->
                <tr>
                  <td style="background-color:#0F172A;padding:44px 40px 36px;text-align:center;">
                    <img src="{LogoDataUri}" alt="Verbo+" height="56" style="display:block;margin:0 auto;border:0;"/>
                  </td>
                </tr>

                <!-- Content section -->
                <tr>
                  <td style="background-color:#0F172A;padding:0 40px 48px;">
                    {body}
                  </td>
                </tr>

                <!-- Footer -->
                <tr>
                  <td style="border-top:1px solid rgba(255,255,255,0.08);background-color:#080E1C;padding:24px 40px;text-align:center;">
                    <p style="margin:0 0 6px;font-size:12px;color:#475569;">
                      Verbo+ · Organize sua igreja. Transforme vidas.
                    </p>
                    <p style="margin:0;font-size:12px;color:#334155;">
                      <a href="{AppUrl}" style="color:#7C3AED;text-decoration:none;">app.verboplus.com.br</a>
                      &nbsp;·&nbsp;
                      <a href="{AppUrl}/configuracoes/privacidade" style="color:#475569;text-decoration:none;">Cancelar recebimento</a>
                    </p>
                  </td>
                </tr>

              </table>
            </td></tr>
          </table>
        </body>
        </html>
        """;

    private static string EscapeHtml(string s) =>
        s.Replace("&", "&amp;").Replace("<", "&lt;").Replace(">", "&gt;").Replace("\"", "&quot;");
}
